const body        = $input.first().json.body;
const user_id     = body.user_id     || '';
const session_id  = body.session_id  || '';
const tool_id     = body.tool_id     || 'general_question';
const raw_output  = body.raw_output  || '';
const output_type = (body.output_type || 'text').toLowerCase().trim();

// ── Format by type ──────────────────────────────────────────────
let formatted_output;
let formatted_for_storage;

switch (output_type) {

  case 'list':
    // Split on newline (or numbered lines), strip blanks
    formatted_output = raw_output
      .split('\n')
      .map(l => l.replace(/^\s*[\-\*•\d]+[.)\s]+/, '').trim())
      .filter(Boolean);
    formatted_for_storage = JSON.stringify(formatted_output);
    break;

  case 'json':
    try {
      const parsed = JSON.parse(raw_output);
      formatted_output      = JSON.stringify(parsed, null, 2);
      formatted_for_storage = formatted_output;
    } catch (_) {
      // Not valid JSON — store as-is with a warning prefix
      formatted_output      = raw_output.trim();
      formatted_for_storage = formatted_output;
    }
    break;

  case 'email':
    // Preserve line breaks, trim leading/trailing whitespace on each line
    formatted_output = raw_output
      .split('\n')
      .map(l => l.trimEnd())
      .join('\n')
      .trim();
    formatted_for_storage = formatted_output;
    break;

  case 'script':
    // Preserve exact content; just trim outer whitespace
    formatted_output      = raw_output.trim();
    formatted_for_storage = formatted_output;
    break;

  case 'text':
  default:
    formatted_output      = raw_output.trim();
    formatted_for_storage = formatted_output;
    break;
}

// ── Tool name map for notification message ───────────────────────
const toolNames = {
  lead_gen:            'Lead Generation',
  copywriting:         'Copywriting',
  offer_building:      'Offer Builder',
  funnel_mapping:      'Funnel Mapper',
  content_calendar:    'Content Calendar',
  ad_strategy:         'Ad Strategy',
  email_sequence:      'Email Sequence',
  seo_brief:           'SEO Brief',
  competitor_research: 'Competitor Research',
  social_planning:     'Social Planning',
  sales_script:        'Sales Script',
  brand_voice:         'Brand Voice',
  analytics:           'Analytics',
  automation_build:    'Automation Builder',
  client_reporting:    'Client Reporting',
  general_question:    'AI Assistant'
};
const tool_name = toolNames[tool_id] || tool_id;

return [{
  json: {
    user_id,
    session_id,
    tool_id,
    tool_name,
    output_type,
    raw_output,
    formatted_output,
    formatted_for_storage,
    notification_message: `Your ${tool_name} output is ready.`,
    created_at: new Date().toISOString()
  }
}];
